{"path": "style.css", "content": "/* ===================
   Mochi Project Styles
   =================== */

/* === Variables === */
:root {
  --primary: #ff6f61;
  --primary-dark: #e65a50;
  --secondary: #3498db;
  --secondary-dark: #2980b9;
  --accent: #f39c12;
  --text-dark: #2c3e50;
  --text-light: #ecf0f1;
  --bg-light: #f9f9f9;
  --bg-gradient: linear-gradient(135deg, #e0eafc, #cfdef3);
  --shadow-sm: 0 2px 8px rgba(0,0,0,0.1);
  --shadow-md: 0 4px 12px rgba(0,0,0,0.15);
  --shadow-lg: 0 8px 24px rgba(0,0,0,0.2);
  --radius-sm: 4px;
  --radius-md: 8px;
  --radius-lg: 30px;
  --container-max: 1200px;
  --font-sans: 'Helvetica Neue', Helvetica, Arial, sans-serif;
  --font-serif: Georgia, serif;
}

/* === Reset & Base === */
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
  font-size: 16px;
}

body {
  font-family: var(--font-sans);
  background: var(--bg-gradient);
  color: var(--text-dark);
  line-height: 1.6;
  overflow-x: hidden;
}

/* === Utility Classes === */
.container {
  max-width: var(--container-max);
  margin: 0 auto;
  padding: 20px;
}

.hidden {display: none !important;}
.visible {display: block !important;}

.text-center {text-align: center;}
.text-left {text-align: left;}
.text-right {text-align: right;}

.mt-1 {margin-top: 0.5rem;}
.mt-2 {margin-top: 1rem;}
.mt-3 {margin-top: 1.5rem;}
.mt-4 {margin-top: 2rem;}

.mb-1 {margin-bottom: 0.5rem;}
.mb-2 {margin-bottom: 1rem;}
.mb-3 {margin-bottom: 1.5rem;}
.mb-4 {margin-bottom: 2rem;}

.p-1 {padding: 0.5rem;}
.p-2 {padding: 1rem;}
.p-3 {padding: 1.5rem;}
.p-4 {padding: 2rem;}

/* === Typography === */
h1, h2, h3, h4, h5, h6 {
  font-weight: 700;
  line-height: 1.2;
  color: var(--text-dark);
  margin-bottom: 1rem;
}

h1 {
  font-size: clamp(2rem, 5vw, 3.5rem);
  color: var(--secondary);
  position: relative;
  display: inline-block;
}

h1::after {
  content: '';
  position: absolute;
  bottom: -8px;
  left: 0;
  width: 60px;
  height: 4px;
  background: var(--primary);
  border-radius: 2px;
}

h2 {
  font-size: clamp(1.5rem, 4vw, 2.5rem);
  color: var(--secondary-dark);
}

h3 {
  font-size: 1.5rem;
  color: var(--primary);
}

p {
  margin-bottom: 1rem;
  color: #555;
  font-size: 1rem;
}

.lead {
  font-size: 1.25rem;
  color: #666;
  max-width: 800px;
  margin: 0 auto;
}

/* === Buttons === */
.btn {
  display: inline-block;
  padding: 12px 30px;
  border: none;
  border-radius: var(--radius-lg);
  font-size: 1rem;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
  text-decoration: none;
  position: relative;
  overflow: hidden;
}

.btn-primary {
  background: var(--primary);
  color: #fff;
  box-shadow: var(--shadow-sm);
}

.btn-primary:hover {
  background: var(--primary-dark);
  transform: translateY(-2px);
  box-shadow: var(--shadow-md);
}

.btn-primary:active {
  transform: translateY(0);
}

.btn-secondary {
  background: var(--secondary);
  color: #fff;
  box-shadow: var(--shadow-sm);
}

.btn-secondary:hover {
  background: var(--secondary-dark);
  transform: translateY(-2px);
  box-shadow: var(--shadow-md);
}

.btn-outline {
  background: transparent;
  border: 2px solid var(--primary);
  color: var(--primary);
}

.btn-outline:hover {
  background: var(--primary);
  color: #fff;
}

/* === Links === */
a {
  color: var(--secondary);
  text-decoration: none;
  transition: color 0.3s ease;
}

a:hover {
  color: var(--primary);
  text-decoration: underline;
}

/* === Navigation === */
.navbar {
  background: #fff;
  box-shadow: var(--shadow-md);
  position: sticky;
  top: 0;
  z-index: 1000;
  padding: 15px 0;
}

.nav-container {
  max-width: var(--container-max);
  margin: 0 auto;
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 0 20px;
}

.nav-logo {
  font-size: 1.8rem;
  font-weight: 800;
  color: var(--primary);
  text-transform: uppercase;
  letter-spacing: 1px;
}

.nav-links {
  display: flex;
  list-style: none;
  gap: 30px;
}

.nav-links a {
  color: var(--text-dark);
  font-weight: 500;
  padding: 8px 12px;
  border-radius: var(--radius-sm);
  transition: all 0.3s ease;
}

.nav-links a:hover {
  background: var(--primary);
  color: #fff;
  text-decoration: none;
}

.nav-toggle {
  display: none;
  font-size: 1.5rem;
  cursor: pointer;
}

/* === Hero Section === */
.hero {
  background: url('https://picsum.photos/seed/mochi/1200/400') center/cover no-repeat;
  color: #fff;
  text-align: center;
  padding: 120px 20px;
  position: relative;
}

.hero::before {
  content: '';
  position: absolute;
  top: 0; left: 0; right: 0; bottom: 0;
  background: rgba(0,0,0,0.4);
  z-index: 1;
}

.hero-content {
  position: relative;
  z-index: 2;
  max-width: 800px;
  margin: 0 auto;
}

.hero h1 {
  font-size: clamp(2.5rem, 6vw, 4.5rem);
  margin-bottom: 1rem;
  color: #fff;
}

.hero h1::after {
  display: none;
}

.hero .tagline {
  font-size: 1.5rem;
  margin-bottom: 2rem;
  color: #fff;
  font-weight: 300;
}

.hero .cta-button {
  display: inline-block;
  padding: 15px 40px;
  background: var(--primary);
  color: #fff;
  border-radius: var(--radius-lg);
  text-decoration: none;
  font-weight: bold;
  font-size: 1.1rem;
  transition: all 0.3s ease;
  box-shadow: var(--shadow-md);
}

.hero .cta-button:hover {
  background: var(--primary-dark);
  transform: translateY(-3px);
  box-shadow: var(--shadow-lg);
}

/* === Features Section === */
.features-section {
  padding: 80px 20px;
  background: #fff;
  text-align: center;
}

.features-section h2 {
  margin-bottom: 60px;
}

.features-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: 30px;
  max-width: var(--container-max);
  margin: 0 auto;
  padding: 0 20px;
}

.feature-card {
  background: var(--bg-light);
  padding: 30px;
  border-radius: var(--radius-md);
  box-shadow: var(--shadow-sm);
  transition: all 0.3s ease;
  position: relative;
  overflow: hidden;
}

.feature-card:hover {
  transform: translateY(-5px);
  box-shadow: var(--shadow-lg);
}

.feature-card::before {
  content: '';
  position: absolute;
  top: 0; left: 0; right: 0; height: 4px;
  background: var(--primary);
  transform: scaleX(0);
  transition: transform 0.3s ease;
}

.feature-card:hover::before {
  transform: scaleX(1);
}

.feature-icon {
  font-size: 2.5rem;
  color: var(--primary);
  margin-bottom: 20px;
}

.feature-card h3 {
  margin-bottom: 15px;
  color: var(--text-dark);
}

.feature-card p {
  color: #666;
  line-height: 1.6;
}

/* === Benefits Section === */
.benefits-section {
  background: var(--bg-light);
  padding: 80px 20px;
  text-align: center;
}

.benefits-section h2 {
  margin-bottom: 50px;
}

.benefits-list {
  list-style: none;
  padding: 0;
  margin: 0 auto 30px;
  max-width: 700px;
  text-align: left;
}

.benefits-list li {
  margin: 15px 0;
  padding-left: 35px;
  position: relative;
  font-size: 1.1rem;
}

.benefits-list li::before {
  content: '✓';
  position: absolute;
  left: 0;
  color: var(--primary);
  font-weight: bold;
  font-size: 1.2rem;
}

.benefits-cta {
  font-weight: bold;
  color: var(--primary);
  font-size: 1.2rem;
}

/* === Testimonials Section === */
.testimonials-section {
  background: #fff;
  padding: 80px 20px;
  text-align: center;
}

.testimonials-section h2 {
  margin-bottom: 60px;
}

.testimonials-container {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 40px;
  max-width: var(--container-max);
  margin: 0 auto;
  padding: 0 20px;
}

.testimonial {
  background: var(--bg-light);
  padding: 30px;
  border-radius: var(--radius-md);
  box-shadow: var(--shadow-sm);
  transition: transform 0.3s ease;
}

.testimonial:hover {
  transform: translateY(-5px);
  box-shadow: var(--shadow-md);
}

.quote {
  font-size: 1.2rem;
  color: var(--text-dark);
  margin-bottom: 20px;
  font-style: italic;
  position: relative;
}

.quote::before, .quote::after {
  content: '"';
  font-size: 1.5rem;
  color: var(--primary);
}

.author {
  font-weight: 600;
  color: var(--primary-dark);
  margin-top: 15px;
  display: block;
}

/* === Contact Section === */
.contact-section {
  background: var(--bg-gradient);
  padding: 80px 20px;
  text-align: center;
}

.contact-section h2 {
  margin-bottom: 50px;
}

.contact-form {
  display: flex;
  flex-direction: column;
  max-width: 600px;
  margin: 0 auto;
  background: #fff;
  padding: 40px;
  border-radius: var(--radius-md);
  box-shadow: var(--shadow-md);
}

.contact-form input,
.contact-form textarea {
  padding: 14px 16px;
  margin: 12px 0;
  border: 2px solid #e0e0e0;
  border-radius: var(--radius-sm);
  font-size: 1rem;
  transition: border-color 0.3s ease;
  font-family: inherit;
}

.contact-form input:focus,
.contact-form textarea:focus {
  outline: none;
  border-color: var(--secondary);
  box-shadow: 0 0 0 3px rgba(52, 152, 219, 0.1);
}

.contact-form textarea {
  min-height: 150px;
  resize: vertical;
}

.contact-form button {
  background: var(--secondary);
  color: #fff;
  border: none;
  padding: 16px;
  border-radius: var(--radius-sm);
  cursor: pointer;
  font-size: 1.1rem;
  margin-top: 20px;
  transition: all 0.3s ease;
  font-weight: 600;
}

.contact-form button:hover {
  background: var(--secondary-dark);
  transform: translateY(-2px);
  box-shadow: var(--shadow-md);
}

/* === Footer === */
.footer {
  background: var(--text-dark);
  color: var(--text-light);
  padding: 60px 20px 20px;
  text-align: center;
}

.footer-content {
  max-width: var(--container-max);
  margin: 0 auto;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 40px;
  margin-bottom: 40px;
  text-align: left;
}

.footer-section h3 {
  color: #fff;
  margin-bottom: 20px;
  font-size: 1.3rem;
}

.footer-section p,
.footer-section a {
  color: #bdc3c7;
  line-height: 1.6;
  font-size: 0.95rem;
}

.footer-section a:hover {
  color: var(--primary);
}

.footer-bottom {
  border-top: 1px solid rgba(255,255,255,0.1);
  padding-top: 20px;
  font-size: 0.9rem;
  color: #95a5a6;
}

/* === Animations === */
@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(30px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes pulse {
  0%, 100% {
    transform: scale(1);
  }
  50% {
    transform: scale(1.05);
  }
}

.animate-fade-in {
  animation: fadeInUp 0.6s ease-out;
}

.animate-pulse {
  animation: pulse 2s infinite;
}

/* === Responsive Design === */
@media (max-width: 768px) {
  .nav-links {
    position: absolute;
    top: 70px;
    left: 0;
    width: 100%;
    background: #fff;
    flex-direction: column;
    align-items: center;
    padding: 20px 0;
    box-shadow: var(--shadow-md);
    transform: translateY(-150%);
    transition: transform 0.3s ease;
  }

  .nav-links.active {
    transform: translateY(0);
  }

  .nav-toggle {
    display: block;
  }

  .hero {
    padding: 80px 20px;
  }

  .hero h1 {
    font-size: 2.5rem;
  }

  .features-grid,
  .testimonials-container,
  .footer-content {
    grid-template-columns: 1fr;
  }

  .contact-form {
    padding: 30px 20px;
  }
}

/* === Utility Spacing === */
.mt-auto {margin-top: auto;}
.mb-auto {margin-bottom: auto;}

/* === Loading Spinner === */
.spinner {
  width: 40px;
  height: 40px;
  border: 4px solid #f3f3f3;
  border-top: 4px solid var(--primary);
  border-radius: 50%;
  animation: spin 1s linear infinite;
  margin: 20px auto;
}

@keyframes spin {
  0% {transform: rotate(0deg);}
  100% {transform: rotate(360deg);}
}

/* === Form Validation Styles === */
.form-group {
  position: relative;
  margin-bottom: 20px;
}

.form-group.error input,
.form-group.error textarea {
  border-color: #e74c3c;
}

.form-group.success input,
.form-group.success textarea {
  border-color: #27ae60;
}

.error-message {
  color: #e74c3c;
  font-size: 0.85rem;
  margin-top: 5px;
  display: none;
}

.form-group.error .error-message {
  display: block;
}

/* === Back to Top Button === */
.back-to-top {
  position: fixed;
  bottom: 30px;
  right: 30px;
  width: 50px;
  height: 50px;
  background: var(--primary);
  color: #fff;
  border: none;
  border-radius: 50%;
  cursor: pointer;
  font-size: 1.2rem;
  box-shadow: var(--shadow-md);
  opacity: 0;
  visibility: hidden;
  transition: all 0.3s ease;
  z-index: 999;
}

.back-to-top.visible {
  opacity: 1;
  visibility: visible;
}

.back-to-top:hover {
  background: var(--primary-dark);
  transform: translateY(-3px);
}

/* === Section Spacing === */
section {
  padding: 100px 0;
}

/* === Color Utilities === */
.text-primary {color: var(--primary);}
.text-secondary {color: var(--secondary);}
.text-accent {color: var(--accent);}

.bg-primary {background: var(--primary);}
.bg-secondary {background: var(--secondary);}
.bg-light {background: var(--bg-light);}

/* === Card Hover Effects === */
.card-hover {
  transition: all 0.3s ease;
}

.card-hover:hover {
  transform: translateY(-10px) scale(1.02);
  box-shadow: var(--shadow-lg);
}

/* === Badge Component === */
.badge {
  display: inline-block;
  padding: 4px 12px;
  background: var(--primary);
  color: #fff;
  border-radius: 20px;
  font-size: 0.85rem;
  font-weight: 600;
  margin-left: 10px;
  vertical-align: middle;
}

/* === Progress Bar === */
.progress {
  width: 100%;
  height: 10px;
  background: #e0e0e0;
  border-radius: 5px;
  overflow: hidden;
  margin: 10px 0;
}

.progress-bar {
  height: 100%;
  background: var(--secondary);
  width: 0%;
  transition: width 0.5s ease;
}

/* === Modal === */
.modal {
  position: fixed;
  top: 0; left: 0; right: 0; bottom: 0;
  background: rgba(0,0,0,0.5);
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0;
  visibility: hidden;
  transition: all 0.3s ease;
  z-index: 2000;
}

.modal.active {
  opacity: 1;
  visibility: visible;
}

.modal-content {
  background: #fff;
  padding: 40px;
  border-radius: var(--radius-md);
  max-width: 500px;
  width: 90%;
  box-shadow: var(--shadow-lg);
}

.close-modal {
  margin-top: 20px;
  padding: 10px 30px;
  background: var(--primary);
  color: #fff;
  border: none;
  border-radius: var(--radius-sm);
  cursor: pointer;
}

/* === Toast Notification === */
.toast {
  position: fixed;
  bottom: 30px;
  left: 50%;
  transform: translateX(-50%);
  background: #27ae60;
  color: #fff;
  padding: 15px 30px;
  border-radius: var(--radius-sm);
  box-shadow: var(--shadow-md);
  opacity: 0;
  transition: opacity 0.3s ease;
  z-index: 3000;
}

.toast.show {
  opacity: 1;
}

/* === Code Block === */
code {
  background: #f4f4f4;
  padding: 2px 6px;
  border-radius: 3px;
  font-family: 'Courier New', Courier, monospace;
  font-size: 0.9em;
  color: #c7254e;
}

pre {
  background: #2d2d2d;
  color: #f8f8f2;
  padding: 20px;
  border-radius: var(--radius-md);
  overflow-x: auto;
  margin: 20px 0;
}

pre code {
  background: transparent;
  color: inherit;
  padding: 0;
}

/* === Breadcrumbs === */
.breadcrumbs {
  display: flex;
  list-style: none;
  padding: 20px 0;
  font-size: 0.9rem;
}

.breadcrumbs li + li::before {
  content: '/';
  margin: 0 8px;
  color: #999;
}

/* === Table === */
table {
  width: 100%;
  border-collapse: collapse;
  margin: 20px 0;
}

th, td {
  padding: 12px 15px;
  border: 1px solid #ddd;
  text-align: left;
}

th {
  background: var(--bg-light);
  font-weight: 600;
}

tr:nth-child(even) {
  background: #f9f9f9;
}

/* === SVG Icon Styles === */
svg.icon {
  width: 24px;
  height: 24px;
  fill: currentColor;
  vertical-align: middle;
}

/* === Print Styles === */
@media print {
  .navbar, .footer, .back-to-top, .toast {
    display: none;
  }

  body {
    background: #fff;
    color: #000;
  }

  .container {
    max-width: 100%;
    padding: 0;
  }

  a {
    color: #000;
    text-decoration: underline;
  }

  .btn {
    border: 1px solid #000;
    background: #fff;
    color: #000;
  }
}

/* === Debug Info (Remove in Production) === */
.debug-info {
  position: fixed;
  top: 10px;
  right: 10px;
  background: #000;
  color: #0f0;
  padding: 10px;
  border-radius: 5px;
  font-family: monospace;
  font-size: 0.8rem;
  z-index: 9999;
  pointer-events: none;
}"}

