   Mochi Cyber‑Tech Styles
   =================== */

/* === Variables === */
:root {
  --bg-dark: #050510;
  --bg-panel: #0f0f1a;
  --primary: #bb86fc;       /* violet pur */
  --primary-dark: #9b5de5;
  --secondary: #03dac6;     /* cyan cyber */
  --accent: #ff5252;         /* rouge néon */
  --text-main: #e0e0e0;
  --text-muted: #a0a0b0;
  --border: rgba(187, 134, 252, 0.3);
  --shadow-sm: 0 2px 8px rgba(0,0,0,0.6);
  --shadow-md: 0 4px 16px rgba(187, 134, 252, 0.4);
  --shadow-lg: 0 8px 32px rgba(3, 218, 198, 0.3);
  --radius: 6px;
  --font-mono: 'Courier New', Courier, monospace;
  --font-sans: 'Inter', system-ui, sans-serif;
}

/* === Reset === */
*, *::before, *::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
  font-size: 16px;
  background: var(--bg-dark);
  color: var(--text-main);
  font-family: var(--font-sans);
}

body {
  line-height: 1.6;
  overflow-x: hidden;
  background: radial-gradient(circle at 20% 20%, rgba(187,134,252,0.08), transparent 40%),
              radial-gradient(circle at 80% 80%, rgba(3,218,198,0.08), transparent 40%);
}

/* === Utilities === */
.container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
}

.hidden {display: none !important;}
.visible {display: block !important;}

.text-center {text-align: center;}
.text-left {text-align: left;}

.mt-1 {margin-top: 0.5rem;}
.mb-1 {margin-bottom: 0.5rem;}

/* === Typography === */
h1, h2, h3, h4, h5, h6 {
  font-weight: 700;
  line-height: 1.2;
  color: var(--primary);
  margin-bottom: 1rem;
  text-transform: uppercase;
  letter-spacing: 1px;
}

h1 {
  font-size: clamp(2.5rem, 5vw, 4.5rem);
  text-shadow: 0 0 10px var(--primary);
}

h2 {
  font-size: clamp(2rem, 4vw, 3rem);
  border-bottom: 2px solid var(--secondary);
  display: inline-block;
  padding-bottom: 0.5rem;
}

p {
  color: var(--text-main);
  margin-bottom: 1rem;
}

.lead {
  font-size: 1.25rem;
  color: var(--text-muted);
}

/* === Buttons === */
.btn {
  display: inline-block;
  padding: 12px 28px;
  border: none;
  border-radius: var(--radius);
  font-weight: 600;
  text-transform: uppercase;
  cursor: pointer;
  transition: all 0.3s ease;
  position: relative;
  overflow: hidden;
  z-index: 1;
  background: transparent;
  color: var(--primary);
  border: 2px solid var(--primary);
}

.btn::before {
  content: '';
  position: absolute;
  top: 0; left: -100%;
  width: 100%; height: 100%;
  background: var(--primary);
  transition: left 0.3s ease;
  z-index: -1;
}

.btn:hover::before {
  left: 0;
}

.btn:hover {
  color: var(--bg-dark);
  box-shadow: 0 0 15px var(--primary);
}

.btn-primary {
  background: var(--primary);
  color: var(--bg-dark);
  border-color: var(--primary);
}

.btn-primary:hover {
  background: transparent;
  color: var(--primary);
  box-shadow: 0 0 20px var(--primary);
}

/* === Navigation === */
.navbar {
  background: rgba(5,5,16,0.9);
  backdrop-filter: blur(10px);
  border-bottom: 1px solid var(--border);
  position: sticky;
  top: 0;
  z-index: 1000;
  padding: 15px 0;
}

.nav-container {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.nav-logo {
  font-size: 1.8rem;
  font-weight: 900;
  color: var(--primary);
  text-decoration: none;
  text-shadow: 0 0 8px var(--primary);
}

.nav-links {
  display: flex;
  list-style: none;
  gap: 25px;
}

.nav-links a {
  color: var(--text-main);
  text-decoration: none;
  font-weight: 500;
  padding: 8px 12px;
  border-radius: var(--radius);
  transition: all 0.3s ease;
  position: relative;
}

.nav-links a::after {
  content: '';
  position: absolute;
  bottom: -3px; left: 0;
  width: 0; height: 2px;
  background: var(--secondary);
  transition: width 0.3s ease;
}

.nav-links a:hover::after {
  width: 100%;
}

.nav-links a:hover {
  color: var(--secondary);
  text-shadow: 0 0 6px var(--secondary);
}

.nav-toggle {
  display: none;
  font-size: 1.5rem;
  color: var(--primary);
  cursor: pointer;
}

/* === Hero === */
.hero {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  text-align: center;
  background: url('https://picsum.photos/seed/cyber/1200/800') center/cover fixed;
  position: relative;
  overflow: hidden;
}

.hero::before {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(to bottom, rgba(5,5,16,0.7), rgba(5,5,16,0.9));
  z-index: 1;
}

.hero-content {
  position: relative;
  z-index: 2;
  max-width: 900px;
  padding: 0 20px;
}

.hero h1 {
  margin-bottom: 1.5rem;
}

.hero .tagline {
  font-size: 1.5rem;
  color: var(--text-muted);
  margin-bottom: 2.5rem;
}

/* === Features === */
.features {
  padding: 100px 0;
  background: var(--bg-panel);
}

.features h2 {
  text-align: center;
  margin-bottom: 60px;
}

.grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: 30px;
  padding: 0 20px;
}

.card {
  background: rgba(255,255,255,0.03);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 30px;
  transition: all 0.4s ease;
  position: relative;
  overflow: hidden;
}

.card::before {
  content: '';
  position: absolute;
  top: 0; left: 0;
  width: 4px; height: 100%;
  background: var(--primary);
  transform: scaleY(0);
  transition: transform 0.4s ease;
  transform-origin: bottom;
}

.card:hover::before {
  transform: scaleY(1);
}

.card:hover {
  transform: translateY(-5px);
  box-shadow: var(--shadow-md);
  border-color: var(--secondary);
}

.card h3 {
  margin-bottom: 15px;
  color: var(--secondary);
}

.card p {
  color: var(--text-muted);
}

/* === Benefits === */
.benefits {
  padding: 100px 0;
  background: var(--bg-dark);
}

.benefits h2 {
  text-align: center;
  margin-bottom: 50px;
}

.benefits ul {
  list-style: none;
  max-width: 800px;
  margin: 0 auto;
}

.benefits li {
  padding: 15px 0;
  border-bottom: 1px solid var(--border);
  position: relative;
  padding-left: 40px;
}

.benefits li::before {
  content: '▸';
  position: absolute;
  left: 0;
  color: var(--primary);
  font-size: 1.5rem;
}

/* === Testimonials === */
.testimonials {
  padding: 100px 0;
  background: var(--bg-panel);
}

.testimonials h2 {
  text-align: center;
  margin-bottom: 60px;
}

.quote {
  background: rgba(255,255,255,0.05);
  border-left: 3px solid var(--accent);
  padding: 30px;
  margin: 20px auto;
  max-width: 800px;
  border-radius: var(--radius);
  font-style: italic;
  color: var(--text-main);
  position: relative;
}

.quote::before {
  content: '"';
  position: absolute;
  top: -20px; left: 10px;
  font-size: 5rem;
  color: var(--accent);
  opacity: 0.2;
}

/* === Footer === */
.footer {
  background: #020205;
  border-top: 1px solid var(--border);
  padding: 60px 0 30px;
  text-align: center;
}

.footer p {
  color: var(--text-muted);
  margin-bottom: 20px;
}

.footer a {
  color: var(--primary);
  text-decoration: none;
}

.footer a:hover {
  text-decoration: underline;
}

/* === Animations === */
@keyframes flicker {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.8; }
}

@keyframes glow {
  0%, 100% { text-shadow: 0 0 10px var(--primary); }
  50% { text-shadow: 0 0 20px var(--secondary); }
}

.animate-flicker { animation: flicker 3s infinite; }
.animate-glow { animation: glow 2s infinite; }

/* === Responsive === */
@media (max-width: 768px) {
  .nav-links {
    position: absolute;
    top: 70px;
    right: 0;
    width: 200px;
    background: var(--bg-panel);
    flex-direction: column;
    align-items: flex-start;
    padding: 20px;
    border-left: 1px solid var(--border);
    transform: translateX(100%);
    transition: transform 0.3s ease;
  }

  .nav-links.active {
    transform: translateX(0);
  }

  .nav-toggle {
    display: block;
  }

  .hero h1 {
    font-size: 2.5rem;
  }

  .grid {
    grid-template-columns: 1fr;
  }
}

/* === Utility Spacing === */
.mt-auto {margin-top: auto;}
.mb-auto {margin-bottom: auto;}

/* === Back to Top === */
.back-to-top {
  position: fixed;
  bottom: 30px;
  right: 30px;
  width: 50px;
  height: 50px;
  background: var(--primary);
  color: var(--bg-dark);
  border: none;
  border-radius: 50%;
  cursor: pointer;
  font-size: 1.5rem;
  box-shadow: 0 0 15px var(--primary);
  opacity: 0;
  visibility: hidden;
  transition: all 0.3s ease;
  z-index: 999;
}

.back-to-top.visible {
  opacity: 1;
  visibility: visible;
}

.back-to-top:hover {
  background: var(--secondary);
  box-shadow: 0 0 25px var(--secondary);
}

/* === Scrollbar === */
::-webkit-scrollbar {
  width: 8px;
}

::-webkit-scrollbar-track {
  background: var(--bg-dark);
}

::-webkit-scrollbar-thumb {
  background: var(--primary);
  border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--secondary);
}"}

