  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: 30px;
  padding: 0 20px;
}

.card {
  background: rgba(255,255,255,0.03);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 30px;
  transition: all 0.4s ease;
  position: relative;
  overflow: hidden;
}

.card::before {
  content: '';
  position: absolute;
  top: 0; left: 0;
  width: 4px; height: 100%;
  background: var(--primary);
  transform: scaleY(0);
  transition: transform 0.4s ease;
  transform-origin: bottom;
}

.card:hover::before {
  transform: scaleY(1);
}

.card:hover {
  transform: translateY(-5px);
  box-shadow: var(--shadow-md);
  border-color: var(--secondary);
}

.card h3 {
  margin-bottom: 15px;
  color: var(--secondary);
}

.card p {
  color: var(--text-muted);
}

/* === Benefits === */
.benefits {
  padding: 100px 0;
  background: var(--bg-dark);
}

.benefits h2 {
  text-align: center;
  margin-bottom: 50px;
}

.benefits ul {
  list-style: none;
  max-width: 800px;
  margin: 0 auto;
}

.benefits li {
  padding: 15px 0;
  border-bottom: 1px solid var(--border);
  position: relative;
  padding-left: 40px;
}

.benefits li::before {
  content: '▸';
  position: absolute;
  left: 0;
  color: var(--primary);
  font-size: 1.5rem;
}

/* === Testimonials === */
.testimonials {
  padding: 100px 0;
  background: var(--bg-panel);
}

.testimonials h2 {
  text-align: center;
  margin-bottom: 60px;
}

.quote {
  background: rgba(255,255,255,0.05);
  border-left: 3px solid var(--accent);
  padding: 30px;
  margin: 20px auto;
  max-width: 800px;
  border-radius: var(--radius);
  font-style: italic;
  color: var(--text-main);
  position: relative;
}

.quote::before {
  content: '"';
  position: absolute;
  top: -20px; left: 10px;
  font-size: 5rem;
  color: var(--accent);
  opacity: 0.2;
}

/* === Contact Section === */
.contact-section {
  padding: 100px 0;
  background: var(--bg-dark);
  text-align: center;
}

.contact-section h2 {
  margin-bottom: 50px;
}

.contact-form {
  display: flex;
  flex-direction: column;
  max-width: 600px;
  margin: 0 auto;
  background: rgba(255,255,255,0.03);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 40px;
  box-shadow: var(--shadow-md);
}

.contact-form input,
.contact-form textarea {
  padding: 14px 16px;
  margin: 12px 0;
  border: 2px solid var(--border);
  border-radius: var(--radius);
  font-size: 1rem;
  background: var(--bg-panel);
  color: var(--text-main);
  transition: border-color 0.3s ease, box-shadow 0.3s ease;
}

.contact-form input:focus,
.contact-form textarea:focus {
  outline: none;
  border-color: var(--secondary);
  box-shadow: 0 0 8px rgba(3,218,198,0.4);
}

.contact-form textarea {
  min-height: 150px;
  resize: vertical;
}

.contact-form button {
  background: var(--primary);
  color: var(--bg-dark);
  border: none;
  padding: 16px;
  border-radius: var(--radius);
  cursor: pointer;
  font-size: 1.1rem;
  margin-top: 20px;
  transition: all 0.3s ease;
  font-weight: 600;
  text-transform: uppercase;
}

.contact-form button:hover {
  background: var(--secondary);
  box-shadow: 0 0 20px var(--secondary);
  transform: translateY(-2px);
}

/* === Footer === */
.footer {
  background: #020205;
  border-top: 1px solid var(--border);
  padding: 60px 0 30px;
  text-align: center;
}

.footer p {
  color: var(--text-muted);
  margin-bottom: 20px;
}

.footer a {
  color: var(--primary);
  text-decoration: none;
}

.footer a:hover {
  text-decoration: underline;
}

/* === Animations === */
@keyframes flicker {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.8; }
}

@keyframes glow {
  0%, 100% { text-shadow: 0 0 10px var(--primary); }
  50% { text-shadow: 0 0 20px var(--secondary); }
}

.animate-flicker { animation: flicker 3s infinite; }
.animate-glow { animation: glow 2s infinite; }

/* === Responsive === */
@media (max-width: 768px) {
  .nav-links {
    position: absolute;
    top: 70px;
    right: 0;
    width: 200px;
    background: var(--bg-panel);
    flex-direction: column;
    align-items: flex-start;
    padding: 20px;
    border-left: 1px solid var(--border);
    transform: translateX(100%);
    transition: transform 0.3s ease;
  }

  .nav-links.active {
    transform: translateX(0);
  }

  .nav-toggle {
    display: block;
  }

  .hero h1 {
    font-size: 2.5rem;
  }

  .grid {
    grid-template-columns: 1fr;
  }
}

/* === Utility Spacing === */
.mt-auto {margin-top: auto;}
.mb-auto {margin-bottom: auto;}

/* === Back to Top === */
.back-to-top {
  position: fixed;
  bottom: 30px;
  right: 30px;
  width: 50px;
  height: 50px;
  background: var(--primary);
  color: var(--bg-dark);
  border: none;
  border-radius: 50%;
  cursor: pointer;
  font-size: 1.5rem;
  box-shadow: 0 0 15px var(--primary);
  opacity: 0;
  visibility: hidden;
  transition: all 0.3s ease;
  z-index: 999;
}

.back-to-top.visible {
  opacity: 1;
  visibility: visible;
}

.back-to-top:hover {
  background: var(--secondary);
  box-shadow: 0 0 25px var(--secondary);
}

/* === Scrollbar === */
::-webkit-scrollbar {
  width: 8px;
}

::-webkit-scrollbar-track {
  background: var(--bg-dark);
}

::-webkit-scrollbar-thumb {
  background: var(--primary);
  border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--secondary);
}"}

